css:
.loader {--loader-bg: #ffffff;
  --loader-secondary-color: #2dd4bf;
   width: calc(5*24px);
   height: 42px;
   display: flex;
   color: var(--loader-color, #059669);
   filter: drop-shadow(30px 25px 0 currentColor) drop-shadow(60px 0 0 currentColor) drop-shadow(120px 0 0 currentColor);
   clip-path: inset(0 100% 0 0);
   animation: l11 2s infinite steps(7);
}
.loader:before  {
  content: "";
   width: 24px;
   height: 20px;
   background: currentColor;
   clip-path: polygon(0 50%,30% 40%,100% 0,60% 40%,100% 50%,60% 60%,100% 100%,30% 60%);
}
@keyframes l11  {
  100% {clip-path: inset(0 -30px 0 0)}
}
